#include <stdio.h>

int main()
{
   long long int n;
   long long ans = 0, a = 2, b = 1, c = 0;
   scanf("%lld", &n);
   if(n == 2) {printf("1\n");return 0;}
   else if(n == 3) {printf("2\n");return 0;}
   else
    while(1)
   {
      if(a > n) break;
      ans++;
      c = b;
      b = a;
      a += c;
   }
   printf("%lld", ans);
   return 0;

}

