fn main() {
    let mut bin = String::new();
    let mut input = WordReader::from_stdin(&mut bin);

    let n: i64 = input.p();
    let mut a = 1;
    let mut b = 2;
    let mut sol = 0;
    while b <= n {
        let c = a + b;
        a = b;
        b = c;
        sol += 1;
    }
    println!("{}", sol);
}
